    [Fact]
    public void Test_MetadataAuthorMeta()
    {
        // Extract author from <meta name='author'> tag
        var result = HtmlToMarkdownRs.Convert("<html><head><title>Page</title><meta name=\"author\" content=\"Jane Doe\"></head><body><p>Content</p></body></html>", null);
        Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
        Assert.Equal("Jane Doe", result.Metadata.Document.Author.Trim());
    }

    [Fact]
    public void Test_MetadataCanonicalUrl()
    {
        // Extract canonical URL from <link rel='canonical'> tag
        var result = HtmlToMarkdownRs.Convert("<html><head><title>Page</title><link rel=\"canonical\" href=\"https://example.com/canonical-page\"></head><body><p>Content</p></body></html>", null);
        Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
        Assert.Equal("https://example.com/canonical-page", result.Metadata.Document.CanonicalUrl.Trim());
    }

