    [Fact]
    public void Test_MetadataMicrodataSchemaArticle()
    {
        // Extract schema.org microdata for Article
        var result = HtmlToMarkdownRs.Convert("<html><head><title>Article</title></head><body><article itemscope itemtype=\"https://schema.org/Article\"><h1 itemprop=\"headline\">Breaking News Today</h1><span itemprop=\"author\">Jane Reporter</span><span itemprop=\"datePublished\">2024-04-22</span><div itemprop=\"articleBody\"><p>The article content goes here with important information about the breaking news story.</p></div></article></body></html>", null);
        Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
        Assert.Contains("breaking news today", result.Content.ToString().ToLower());
        Assert.Contains("jane reporter", result.Content.ToString().ToLower());
        Assert.Contains("important information", result.Content.ToString().ToLower());
    }

