    [Fact]
    public void Test_OgBasicTags()
    {
        // Extract og:title, og:description, and og:image from Open Graph meta tags
        var result = HtmlToMarkdownRs.Convert("<html><head><title>Fallback Title</title><meta property=\"og:title\" content=\"OG Title\"><meta property=\"og:description\" content=\"OG description text.\"><meta property=\"og:image\" content=\"https://example.com/image.jpg\"></head><body><p>Content</p></body></html>", null);
        Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
        Assert.Equal("OG Title", result.Metadata.Document.OpenGraph["title"].Trim());
        Assert.Equal("OG description text.", result.Metadata.Document.OpenGraph["description"].Trim());
        Assert.Equal("https://example.com/image.jpg", result.Metadata.Document.OpenGraph["image"].Trim());
    }

    [Fact]
    public void Test_OgMultipleTags()
    {
        // Extract multiple Open Graph tags including type, url, and site_name
        var result = HtmlToMarkdownRs.Convert("<html><head><meta property=\"og:title\" content=\"Article Title\"><meta property=\"og:type\" content=\"article\"><meta property=\"og:url\" content=\"https://example.com/article\"><meta property=\"og:site_name\" content=\"Example Site\"><meta property=\"og:description\" content=\"An interesting article.\"><meta property=\"og:image\" content=\"https://example.com/article.jpg\"></head><body><article><p>Article content here.</p></article></body></html>", null);
        Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
        Assert.Equal("Article Title", result.Metadata.Document.OpenGraph["title"].Trim());
        Assert.Equal("article", result.Metadata.Document.OpenGraph["type"].Trim());
        Assert.Equal("https://example.com/article", result.Metadata.Document.OpenGraph["url"].Trim());
        Assert.Equal("Example Site", result.Metadata.Document.OpenGraph["site_name"].Trim());
    }

    [Fact]
    public void Test_StructuredDataJsonLd()
    {
        // JSON-LD script tag is stripped from output (security) but metadata may be extracted
        var result = HtmlToMarkdownRs.Convert("<html><head><title>Article</title><script type=\"application/ld+json\">{\"@context\":\"https://schema.org\",\"@type\":\"Article\",\"headline\":\"My Article\",\"author\":{\"@type\":\"Person\",\"name\":\"Jane Doe\"},\"datePublished\":\"2024-01-15\"}</script></head><body><h1>My Article</h1><p>Article body text.</p></body></html>", null);
        Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
        Assert.Contains("my article", result.Content.ToString().ToLower());
    }

    [Fact]
    public void Test_StructuredDataMultipleJsonLd()
    {
        // Multiple JSON-LD blocks are all stripped from output
        var result = HtmlToMarkdownRs.Convert("<html><head><title>Shop Page</title><script type=\"application/ld+json\">{\"@context\":\"https://schema.org\",\"@type\":\"Product\",\"name\":\"Widget\",\"price\":\"9.99\"}</script><script type=\"application/ld+json\">{\"@context\":\"https://schema.org\",\"@type\":\"BreadcrumbList\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Home\"}]}</script></head><body><h1>Widget</h1><p>A great widget for all purposes.</p></body></html>", null);
        Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
